import React from 'react';
import '../style/Card.css';
import { useOrderContext } from '../contextAPI/OrderCartContext';

const CartItemCard = ({ name, description, price = 0, quantity = 0, image }) => {
  const totalAmount = price * quantity;
  const { setOrder } = useOrderContext();

  const handleIncrement = () => {
    setOrder(prev => ({
      ...prev,
      [name]: { ...prev[name], quantity: (prev[name]?.quantity || 0) + 1 },
    }));
  };

  const handleDecrement = () => {
    setOrder(prev => {
      if ((prev[name]?.quantity || 0) > 1) {
        return { ...prev, [name]: { ...prev[name], quantity: prev[name].quantity - 1 } };
      } else {
        const newOrder = { ...prev };
        delete newOrder[name];
        return newOrder;
      }
    });
  };

  const handleRemove = () => {
    setOrder(prev => {
      const newOrder = { ...prev };
      delete newOrder[name];
      return newOrder;
    });
  };

  return (
    <div className="cart-item-card">
      <button className="remove-button" onClick={handleRemove} aria-label="Remove item">✕</button>
      {image && <img src={image} alt={name} className="cart-item-image" />}
      <div className="cart-item-details">
        <h3>{name}</h3>
        <p>{description}</p>
        <div className="quantity-controls">
          <button
            onClick={handleDecrement}
            className="quantity-btn"
            aria-label={`Decrease quantity of ${name}`}
          >
            -
          </button>
          <span className="quantity-display">{quantity}</span>
          <button
            onClick={handleIncrement}
            className="quantity-btn"
            aria-label={`Increase quantity of ${name}`}
          >
            +
          </button>
        </div>
        <p>Price: ${price.toFixed(2)}</p>
        <p>Quantity: {quantity}</p>
        <p>Total: ${totalAmount.toFixed(2)}</p>
      </div>
    </div>
  );
};

export default CartItemCard;
